-- Replace the active puzzle bank with puzzles that are valid and uniquely solvable.
-- Generated and verified by npm run validate:puzzles / validate:unique-puzzles.

on conflict (puzzle_id) do update
set
  difficulty = excluded.difficulty,
  givens = excluded.givens,
  solution = excluded.solution,
  rating_score = excluded.rating_score,
  source = excluded.source,
  is_active = excluded.is_active;
